CREATE OR REPLACE VIEW view_sctranssch (data_code, bank_code, trandate, seq_tran, seq_no, membership_no, cmember_name, amount, acc_no, member_group_no, c_reference, eng_name, item_type, branch_bank_code, fee_amount, begining_of_contract, branch_id, loan_type, trans_bank_status, item_seq_no) AS SELECT
        ' ' as data_code,  
        '06' as bank_code ,
        ' ' as trandate,  
        ' ' as seq_tran,  
        row_number() OVER () as seq_no,
        sc_sch_mem_regis.membership_no as membership_no ,
        sc_mem_m_ucf_prename.prename || '' ||
        sc_mem_m_membership_registered.member_name || ' ' ||
        sc_mem_m_membership_registered.member_surname as cmember_name ,
        sc_sch_mem_regis.sch_receive  as amount,
        trim(both sc_sch_mem_regis.bank_accno)  as  acc_no ,
        sc_mem_m_membership_registered.member_group_no as member_group_no,
        sc_sch_mem_regis.requestment_no as c_reference,
        sc_mem_m_membership_registered.eng_name as eng_name ,
         'MRT' as item_type,   
       left((trim(both sc_sch_mem_regis.bank_accno)),3) as branch_bank_code,
        0 as fee_amount,
        sc_sch_mem_regis.approve_date  as begining_of_contract
,'01' as branch_id
, ' ' as loan_type
,sc_sch_mem_regis.trans_bank_status as trans_bank_status
,0 as item_seq_no
FROM 
    sc_sch_mem_regis,
    sc_mem_m_membership_registered
,sc_mem_m_ucf_prename
where 1=1
and sc_mem_m_ucf_prename.prename_code = sc_mem_m_membership_registered.prename_code
and sc_mem_m_membership_registered.membership_no = sc_sch_mem_regis.membership_no
and sc_sch_mem_regis.approve_status = '1'
and sc_sch_mem_regis.cancel_status = '0'
and sc_sch_mem_regis.payment_type_code = 'BNK'

/*WHERE*/

--and sc_sch_mem_regis.approve_date  between adtm_date and adtm_edate
order by sc_sch_mem_regis.school_class
,sc_mem_m_membership_registered.member_group_no
,sc_mem_m_membership_registered.membership_no;

